 43→
 44→    public MainWindow()
 45→    {
 46→        InitializeComponent();
 47→
 48→        // 설정 로드
 49→        _config = AppConfig.Load();
 50→
 51→        // 차트 초기화
 52→        _chartPoints = new ObservableCollection<ObservablePoint>();
 53→        _series = new LineSeries<ObservablePoint>
 54→        {
