 67→            new Axis
 68→            {
 69→                Name = "Time(s)",
 70→                NamePaint = new SolidColorPaint(new SKColor(0x9C, 0xA3, 0xAF)),
 71→                LabelsPaint = new SolidColorPaint(new SKColor(0x9C, 0xA3, 0xAF)),
 72→                SeparatorsPaint = new SolidColorPaint(new SKColor(0x3A, 0x3A, 0x3A))
 73→            }
 74→        };
