299→    /// <summary>
300→    /// SET — 수동 전압 설정
301→    /// </summary>
302→    private void btnSetVolt_Click(object sender, RoutedEventArgs e)
303→    {
304→        if (double.TryParse(txtManualVolt.Text, out double volt))
305→        {
306→            _supply.TargetVolt = volt;
307→            WriteLog($"수동 전압 설정: {volt:F1} V");
308→        }
309→        else
310→        {
311→            WriteLog("전압값 입력 오류");
312→        }
313→    }
314→
315→    #endregion
316→
317→    #region 검사 엔진 이벤트 핸들러
318→
319→    /// <summary>
320→    /// 로그 메시지 수신
321→    /// </summary>
322→    private void Engine_OnLogMessage(string message)
323→    {
324→        Dispatcher.Invoke(() => WriteLog(message));
325→    }
326→
327→    /// <summary>
328→    /// 데이터 포인트 추가
329→    /// </summary>
330→    private void Engine_OnDataPointAdded(double time, double current)
331→    {
332→        Dispatcher.Invoke(() =>
333→        {
334→            _chartPoints.Add(new ObservablePoint(time, current));
335→        });
336→    }
337→
338→    /// <summary>
339→    /// 측정 결과 추가
340→    /// </summary>
341→    private void Engine_OnResultAdded(MeasureResult result)
342→    {
343→        Dispatcher.Invoke(() =>
344→        {
345→            _results.Add(result);
346→        });
347→    }
348→
349→    /// <summary>
350→    /// 검사 완료
351→    /// </summary>
352→    private void Engine_OnCompleted()
353→    {
354→        Dispatcher.Invoke(() =>
355→        {
356→            RestoreButtonColors();
357→            WriteLog("자동 검사 완료");
358→        });
359→    }
360→
361→    /// <summary>
362→    /// 스텝 변경
363→    /// </summary>
364→    private void Engine_OnStepChanged(InspectionStep step)
365→    {
366→        Dispatcher.Invoke(() => WriteLog($"스텝: {step}"));
367→    }
368→
369→    #endregion
370→
371→    #region 유틸리티
372→
373→    /// <summary>
374→    /// 버튼 색상을 기본값으로 복원
375→    /// </summary>
376→    private void RestoreButtonColors()
377→    {
378→        btnAutoStart.Background = new System.Windows.Media.SolidColorBrush(
379→            (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString("#1A3D2E"));
380→        btnAutoStop.Background = new System.Windows.Media.SolidColorBrush(
381→            (System.Windows.Media.Color)System.Windows.Media.ColorConverter.ConvertFromString("#3B1818"));
382→    }
383→
384→    /// <summary>
385→    /// 시스템 로그에 메시지 추가 (최대 15줄 유지)
386→    /// </summary>
387→    private void WriteLog(string message)
388→    {
389→        var timestamp = DateTime.Now.ToString("HH:mm:ss");
390→        var line = $"[{timestamp}] {message}";
391→
392→        // 줄 수 제한
393→        var lines = txtLog.Text.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList();
394→        lines.Add(line);
395→
396→        while (lines.Count > MAX_LOG_LINES)
397→            lines.RemoveAt(0);
398→
399→        txtLog.Text = string.Join("\n", lines);
400→        txtLog.ScrollToEnd();
401→
402→        // 파일 로그에도 기록
403→        Logger.Info(message);
404→    }
405→
406→    #endregion
407→}
