using System.Windows;
using System.Windows.Threading;
using PortableTestMachine2.Core;

namespace PortableTestMachine2;

/// <summary>
/// 애플리케이션 진입점 — 전역 예외 핸들러 등록
/// </summary>
public partial class App : Application
{
    protected override void OnStartup(StartupEventArgs e)
    {
        base.OnStartup(e);

        // 필수 디렉토리 생성
        PathManager.EnsureDirectories();

        // UI 스레드 예외 핸들러
        DispatcherUnhandledException += App_DispatcherUnhandledException;

        // 비UI 스레드 예외 핸들러
        AppDomain.CurrentDomain.UnhandledException += CurrentDomain_UnhandledException;
    }

    /// <summary>
    /// UI 스레드 미처리 예외 — 크래시 로그 기록 후 종료
    /// </summary>
    private void App_DispatcherUnhandledException(object sender, DispatcherUnhandledExceptionEventArgs e)
    {
        Logger.WriteCrashLog(e.Exception);
        MessageBox.Show(
            $"예기치 않은 오류가 발생했습니다.\n{e.Exception.Message}",
            "오류",
            MessageBoxButton.OK,
            MessageBoxImage.Error);
        e.Handled = true;
        Shutdown();
    }

    /// <summary>
    /// 비UI 스레드 미처리 예외 — 크래시 로그 기록
    /// </summary>
    private void CurrentDomain_UnhandledException(object sender, UnhandledExceptionEventArgs e)
    {
        if (e.ExceptionObject is Exception ex)
        {
            Logger.WriteCrashLog(ex);
        }
    }
}

