  1→using PortableTestMachine2.Communication;
  2→using PortableTestMachine2.Inspection.StepHandlers;
  3→using PortableTestMachine2.Models;
  4→
  5→namespace PortableTestMachine2.Inspection;
  6→
  7→/// <summary>
  8→/// 검사 엔진 — 상태머신 기반 CW/CCW 전류 검사 실행
  9→/// 백그라운드 스레드에서 상태별 핸들러를 순차 실행
 10→/// </summary>
 11→public class InspectionEngine : IInspectionCallback
 12→{
 13→    private readonly PowerSupplyService _supply;
 14→    private readonly IoBoardService _ioBoard;
 15→    private readonly InspectionContext _context;
 16→    private readonly Dictionary<InspectionStep, IStepHandler> _handlers;
 17→
 18→    private Thread? _thread;
 19→    private volatile bool _running;
 20→
 21→    // UI 알림 이벤트
 22→    public event Action<string>? LogMessage;
 23→    public event Action<double, double>? DataPointAdded;
 24→    public event Action<MeasureResult>? ResultAdded;
 25→    public event Action? InspectionCompleted;
 26→    public event Action<InspectionStep>? StepChanged;
 27→
 28→    public InspectionEngine(
 29→        PowerSupplyService supply,
 30→        IoBoardService ioBoard,
 31→        InspectionContext context)
 32→    {
 33→        _supply = supply;
 34→        _ioBoard = ioBoard;
 35→        _context = context;
 36→
 37→        // 핸들러 등록
 38→        _handlers = new Dictionary<InspectionStep, IStepHandler>
 39→        {
 40→            // 전압 설정 (Step 10, 11, 12)
 41→            [InspectionStep.SetVoltage] = new SetVoltageHandler(_supply, this),
 42→            [InspectionStep.ApplyVoltage] = new SetVoltageHandler(_supply, this),
 43→            [InspectionStep.ConfirmVoltage] = new SetVoltageHandler(_supply, this),
 44→
 45→            // 검사 초기화 (Step 20)
 46→            [InspectionStep.Initialize] = new InitHandler(this),
 47→
 48→            // 반복 시작 (Step 100)
 49→            [InspectionStep.CycleStart] = new CycleStartHandler(),
 50→
 51→            // CW 측정 (Step 200~204)
