using PortableTestMachine2.Communication;
using PortableTestMachine2.Inspection.StepHandlers;
using PortableTestMachine2.Models;

namespace PortableTestMachine2.Inspection;

/// <summary>
/// 검사 엔진 — 상태머신 기반 CW/CCW 전류 검사 실행
/// 백그라운드 스레드에서 상태별 핸들러를 순차 실행
/// </summary>
public class InspectionEngine : IInspectionCallback
{
    private readonly PowerSupplyService _supply;
    private readonly IoBoardService _ioBoard;
    private readonly InspectionContext _context;
    private readonly Dictionary<InspectionStep, IStepHandler> _handlers;

    private Thread? _thread;
    private volatile bool _running;

    // UI 알림 이벤트
    public event Action<string>? LogMessage;
    public event Action<double, double>? DataPointAdded;
    public event Action<MeasureResult>? ResultAdded;
    public event Action? InspectionCompleted;
    public event Action<InspectionStep>? StepChanged;

    public InspectionEngine(
        PowerSupplyService supply,
        IoBoardService ioBoard,
        InspectionContext context)
    {
        _supply = supply;
        _ioBoard = ioBoard;
        _context = context;

        // 핸들러 등록
        _handlers = new Dictionary<InspectionStep, IStepHandler>
        {
            // 전압 설정 (Step 10, 11, 12)
            [InspectionStep.SetVoltage] = new SetVoltageHandler(_supply, this),
            [InspectionStep.ApplyVoltage] = new SetVoltageHandler(_supply, this),
            [InspectionStep.ConfirmVoltage] = new SetVoltageHandler(_supply, this),

            // 검사 초기화 (Step 20)
            [InspectionStep.Initialize] = new InitHandler(this),

            // 반복 시작 (Step 100)
            [InspectionStep.CycleStart] = new CycleStartHandler(),

            // CW 측정 (Step 200~204)
            [InspectionStep.CwStart] = new CwMeasureHandler(_supply, _ioBoard, this),
            [InspectionStep.CwMeasure] = new CwMeasureHandler(_supply, _ioBoard, this),
            [InspectionStep.CwComplete] = new CwMeasureHandler(_supply, _ioBoard, this),
            [InspectionStep.CwWait] = new CwMeasureHandler(_supply, _ioBoard, this),
            [InspectionStep.CwToCcw] = new CwMeasureHandler(_supply, _ioBoard, this),

            // CCW 측정 (Step 300~301)
            [InspectionStep.CcwStart] = new CcwMeasureHandler(_supply, _ioBoard, this),
            [InspectionStep.CcwMeasure] = new CcwMeasureHandler(_supply, _ioBoard, this),

            // 반복 카운트 (Step 400)
            [InspectionStep.CycleCount] = new CycleCountHandler(_ioBoard, this),

            // 검사 완료 (Step 500)
            [InspectionStep.Complete] = new CompleteHandler(_ioBoard, this),
        };
    }

    /// <summary>
    /// 검사 시작 — 백그라운드 스레드 실행
    /// </summary>
    public void Start()
    {
        if (_running) return;

        _running = true;
        _thread = new Thread(RunLoop)
        {
            Name = "InspectionEngine",
            IsBackground = true
        };
        _thread.Start();
    }

    /// <summary>
    /// 검사 중지 — 모터 OFF, Idle 복귀
    /// </summary>
    public void Stop()
    {
        _running = false;
        _ioBoard.OFF();
        _ioBoard.SendDoFrame();
        _context.CurrentStep = InspectionStep.Idle;
    }

    /// <summary>
    /// 메인 루프 — 200ms 주기로 현재 스텝 실행
    /// </summary>
    private void RunLoop()
    {
        while (_running)
        {
            try
            {
                ExecuteStep();
            }
            catch (Exception ex)
            {
                RaiseLog($"검사 오류: {ex.Message}");
                Stop();
                break;
            }

            Thread.Sleep(200);
        }
    }

    /// <summary>
    /// 현재 스텝에 해당하는 핸들러 실행 및 상태 전환
    /// </summary>
    private void ExecuteStep()
    {
        var currentStep = _context.CurrentStep;

        // Idle 상태에서는 아무것도 하지 않음
        if (currentStep == InspectionStep.Idle)
            return;

        if (_handlers.TryGetValue(currentStep, out var handler))
        {
            var nextStep = handler.Execute(_context);

            // 상태 전환 시 이벤트 발생
            if (nextStep != currentStep)
            {
                _context.CurrentStep = nextStep;
                StepChanged?.Invoke(nextStep);
            }
        }
    }

    // IInspectionCallback 구현
    public void RaiseLog(string message) => LogMessage?.Invoke(message);
    public void RaiseDataPoint(double time, double current) => DataPointAdded?.Invoke(time, current);
    public void RaiseResult(MeasureResult result) => ResultAdded?.Invoke(result);
    public void RaiseCompleted() => InspectionCompleted?.Invoke();
}

