using System.IO.Ports;
using System.Text;

namespace PortableTestMachine2.Communication;

/// <summary>
/// SCPI 전원공급기 통신 서비스
/// 전류 측정 및 전압 설정을 폴링 방식으로 처리
/// </summary>
public class PowerSupplyService : IDeviceService
{
    private SerialPort? _port;
    private bool _isConnected;
    private readonly StringBuilder _recvBuffer = new();
    private double _currentValue;
    private double _targetVolt;
    private readonly object _lock = new();

    // 요청 단계 폴링 상태
    private int _requestStep;
    private DateTime _stepStartTime;

    /// <summary>
    /// 연결 상태
    /// </summary>
    public bool IsConnected => _isConnected;

    /// <summary>
    /// 측정된 전류값 (스레드 안전)
    /// </summary>
    public double CurrentValue
    {
        get { lock (_lock) return _currentValue; }
        private set { lock (_lock) _currentValue = value; }
    }

    /// <summary>
    /// 목표 전압값 (스레드 안전, 설정 시 전압 명령 전송)
    /// </summary>
    public double TargetVolt
    {
        get { lock (_lock) return _targetVolt; }
        set
        {
            lock (_lock) _targetVolt = value;
            SendSetVoltageCommand(value);
        }
    }

    /// <summary>
    /// 시리얼 포트 연결 및 초기화 명령 전송
    /// </summary>
    public bool Connect(string portName)
    {
        try
        {
            _port = new SerialPort(portName)
            {
                BaudRate = PowerSupplyProtocol.BAUD_RATE,
                DataBits = 8,
                Parity = Parity.None,
                StopBits = StopBits.One,
                Handshake = Handshake.XOnXOff
            };

            _port.DataReceived += Port_DataReceived;
            _port.Open();

            // 초기화 명령 전송
            _port.Write(PowerSupplyProtocol.INIT_COMMAND + PowerSupplyProtocol.TERMINATOR);

            _isConnected = true;
            _requestStep = 0;
            _stepStartTime = DateTime.Now;
            return true;
        }
        catch
        {
            _isConnected = false;
            return false;
        }
    }

    /// <summary>
    /// 연결 해제
    /// </summary>
    public void Disconnect()
    {
        try
        {
            if (_port != null)
            {
                _port.DataReceived -= Port_DataReceived;
                if (_port.IsOpen)
                    _port.Close();
                _port.Dispose();
                _port = null;
            }
        }
        catch
        {
            // 안전한 종료
        }
        finally
        {
            _isConnected = false;
        }
    }

    /// <summary>
    /// 수신 데이터 처리 — CR(13) 수신 시 전류값 파싱
    /// </summary>
    private void Port_DataReceived(object sender, SerialDataReceivedEventArgs e)
    {
        if (_port == null || !_port.IsOpen) return;

        try
        {
            int bytesToRead = _port.BytesToRead;
            byte[] buffer = new byte[bytesToRead];
            _port.Read(buffer, 0, bytesToRead);

            lock (_lock)
            {
                foreach (byte b in buffer)
                {
                    if (b == PowerSupplyProtocol.RESPONSE_TERMINATOR)
                    {
                        // CR 수신 — 버퍼 내용을 전류값으로 파싱
                        string response = _recvBuffer.ToString();
                        _recvBuffer.Clear();

                        if (PowerSupplyProtocol.TryParseCurrentResponse(response, out double value))
                        {
                            _currentValue = value;
                        }

                        // 응답 수신 완료 → 다음 단계로 전환
                        if (_requestStep == 1)
                        {
                            _requestStep = 2;
                            _stepStartTime = DateTime.Now;
                        }
                    }
                    else
                    {
                        _recvBuffer.Append((char)b);
                    }
                }
            }
        }
        catch
        {
            // 수신 오류 무시
        }
    }

    /// <summary>
    /// 전류 측정 요청 명령 전송
    /// </summary>
    public void SendMeasureCurrentCommand()
    {
        if (_port == null || !_port.IsOpen) return;
        _port.Write(PowerSupplyProtocol.MEASURE_CURRENT + PowerSupplyProtocol.TERMINATOR);
    }

    /// <summary>
    /// 전압 설정 명령 전송
    /// </summary>
    public void SendSetVoltageCommand(double volt)
    {
        if (_port == null || !_port.IsOpen) return;
        _port.Write(PowerSupplyProtocol.BuildSetVoltageCommand(volt));
    }

    /// <summary>
    /// 외부 타이머에서 호출 — 요청 단계 폴링 진행
    /// Step 0: 전류 측정 요청 → Step 1
    /// Step 1: 응답 대기 (DataReceived에서 처리) → Step 2
    /// Step 2: 전압 설정 전송 → Step 0
    /// 타임아웃: Step 1이 2초 초과 시 Step 0으로 리셋
    /// </summary>
    public void Poll()
    {
        if (!_isConnected) return;

        lock (_lock)
        {
            switch (_requestStep)
            {
                case 0:
                    // 전류 측정 요청
                    SendMeasureCurrentCommand();
                    _requestStep = 1;
                    _stepStartTime = DateTime.Now;
                    break;

                case 1:
                    // 응답 대기 — 타임아웃 확인
                    double elapsed = (DateTime.Now - _stepStartTime).TotalSeconds;
                    if (elapsed > PowerSupplyProtocol.TIMEOUT_SECONDS)
                    {
                        // 타임아웃 — 초기 단계로 리셋
                        _recvBuffer.Clear();
                        _requestStep = 0;
                    }
                    break;

                case 2:
                    // 전압 설정 전송
                    SendSetVoltageCommand(_targetVolt);
                    _requestStep = 0;
                    _stepStartTime = DateTime.Now;
                    break;
            }
        }
    }

    /// <summary>
    /// 리소스 해제
    /// </summary>
    public void Dispose()
    {
        Disconnect();
        GC.SuppressFinalize(this);
    }
}

