using PortableTestMachine2.Models;
using System.Diagnostics;

namespace PortableTestMachine2.Inspection;

/// <summary>
/// 검사 상태 열거형
/// </summary>
public enum InspectionStep
{
    Idle = 0,            // 대기/모니터링
    SetVoltage = 10,     // 전압 설정
    ApplyVoltage = 11,   // 전압 적용
    ConfirmVoltage = 12, // 전압 확인
    Initialize = 20,     // 검사 초기화
    CycleStart = 100,    // 반복 시작
    CwStart = 200,       // CW 구동 시작
    CwMeasure = 201,     // CW 전류 측정
    CwComplete = 202,    // CW 완료 처리
    CwWait = 203,        // CW 후 1초 대기
    CwToCcw = 204,       // CCW 전환 준비
    CcwStart = 300,      // CCW 구동 시작
    CcwMeasure = 301,    // CCW 전류 측정
    CycleCount = 400,    // 반복 카운트 판정
    Complete = 500       // 검사 완료
}

/// <summary>
/// 검사 실행 상태 데이터
/// </summary>
public class InspectionContext
{
    public InspectionStep CurrentStep { get; set; } = InspectionStep.Idle;
    public Stopwatch StepTimer { get; } = new();   // 각 단계별 타이머
    public Stopwatch GraphTimer { get; } = new();   // 그래프 전체 타이머

    public int TestCount { get; set; }        // 현재 반복 횟수
    public int TargetCount { get; set; }      // 목표 반복 횟수
    public double TargetVolt { get; set; }    // 목표 전압
    public string StopMode { get; set; } = "CURRENT"; // 정지 조건
    public double StopValue { get; set; }     // 정지 기준값

    // 전류 측정 데이터 (현재 구간)
    public List<double> CurrentSamples { get; } = new();
    public List<double> TimeSamples { get; } = new();
    public double MaxCurrent { get; set; }    // 현재 구간 최대 전류

    // 전체 결과
    public List<MeasureResult> Results { get; } = new();

    // 경과 시간 (초)
    public double ElapsedSeconds => StepTimer.Elapsed.TotalSeconds;
    public double GraphSeconds => GraphTimer.Elapsed.TotalSeconds;

    /// <summary>
    /// 현재 구간 초기화
    /// </summary>
    public void ResetSamples()
    {
        CurrentSamples.Clear();
        TimeSamples.Clear();
        MaxCurrent = 0;
        StepTimer.Restart();
    }

    /// <summary>
    /// 전체 초기화
    /// </summary>
    public void Reset()
    {
        CurrentStep = InspectionStep.Idle;
        TestCount = 0;
        MaxCurrent = 0;
        CurrentSamples.Clear();
        TimeSamples.Clear();
        Results.Clear();
        StepTimer.Reset();
        GraphTimer.Reset();
    }
}

