using ClosedXML.Excel;
using PortableTestMachine2.Models;

namespace PortableTestMachine2.Data;

/// <summary>
/// 측정 결과를 엑셀 파일로 내보내기
/// </summary>
public static class ExcelExporter
{
    /// <summary>
    /// 측정 결과 리스트를 엑셀 파일로 저장
    /// </summary>
    public static void Export(List<MeasureResult> results, string filePath)
    {
        using var workbook = new XLWorkbook();
        var sheet = workbook.Worksheets.Add("검사결과");

        // 헤더 설정
        string[] headers = ["No", "Info", "Volt(V)", "Current Max(A)", "Time(s)"];
        double[] widths = [8, 20, 12, 16, 12];

        for (int i = 0; i < headers.Length; i++)
        {
            var cell = sheet.Cell(1, i + 1);
            cell.Value = headers[i];
            cell.Style.Font.Bold = true;
            cell.Style.Alignment.Horizontal = XLAlignmentHorizontalValues.Center;
            sheet.Column(i + 1).Width = widths[i];
        }

        // 데이터 행 작성
        for (int row = 0; row < results.Count; row++)
        {
            var r = results[row];
            int excelRow = row + 2; // 헤더 다음 행부터

            sheet.Cell(excelRow, 1).Value = row + 1;          // No (1부터 자동 번호)
            sheet.Cell(excelRow, 2).Value = r.Info;            // Info
            sheet.Cell(excelRow, 3).Value = r.Voltage;         // Volt(V)
            sheet.Cell(excelRow, 4).Value = r.MaxCurrent;      // Current Max(A)
            sheet.Cell(excelRow, 5).Value = r.ElapsedTime;     // Time(s)
        }

        workbook.SaveAs(filePath);
    }
}

