/// <summary>
/// 반복 시작 핸들러 (Step 100)
/// 단계 타이머 초기화 후 CW 구동으로 전환
/// </summary>
public class CycleStartHandler : IStepHandler
{
    public InspectionStep Execute(InspectionContext context)
    {
        context.StepTimer.Restart();
        return InspectionStep.CwStart;
    }
}

