 5→
 6→/// <summary>
 7→/// 반복 카운트 핸들러 (Step 400)
 8→/// CCW 결과 생성 후 반복 횟수 판정 — 미달이면 다음 사이클, 도달이면 완료
 9→/// </summary>
10→public class CycleCountHandler : IStepHandler
11→{
12→    private readonly IoBoardService _ioBoard;
13→    private readonly IInspectionCallback _callback;
14→
15→    public CycleCountHandler(IoBoardService ioBoard, IInspectionCallback callback)
16→    {
17→        _ioBoard = ioBoard;
18→        _callback = callback;
19→    }
20→
21→    public InspectionStep Execute(InspectionContext context)
22→    {
23→        // 최종 최대 전류 계산
24→        context.MaxCurrent = CalculateMaxCurrent(context);
25→
26→        // CCW 결과 생성
27→        var result = new MeasureResult
28→        {
29→            SequenceNo = context.Results.Count + 1,
30→            Direction = "CCW",
31→            Voltage = context.TargetVolt,
32→            MaxCurrent = context.MaxCurrent,
33→            ElapsedTime = context.ElapsedSeconds
34→        };
35→
36→        context.Results.Add(result);
37→        _callback.RaiseResult(result);
38→        _callback.RaiseLog($"CCW 완료 — 최대전류: {result.MaxCurrent:F3}A, 시간: {result.ElapsedTime:F1}s");
39→
40→        // 반복 카운트 증가
41→        context.TestCount++;
42→
43→        // 모터 OFF
44→        _ioBoard.OFF();
45→        _ioBoard.SendDoFrame();
46→
47→        // 반복 횟수 판정
48→        if (context.TestCount < context.TargetCount)
49→        {
50→            _callback.RaiseLog($"반복 {context.TestCount}/{context.TargetCount} 완료 — 다음 사이클");
51→            return InspectionStep.CycleStart;
52→        }
53→        else
54→        {
55→            return InspectionStep.Complete;
56→        }
57→    }
58→
59→    /// <summary>
60→    /// 최대 전류 계산 — 앞 1초, 뒤 1초 구간 제외
61→    /// </summary>
62→    private static double CalculateMaxCurrent(InspectionContext context)
63→    {
64→        double maxCurrent = 0;
