using PortableTestMachine2.Communication;

namespace PortableTestMachine2.Inspection.StepHandlers;

/// <summary>
/// 검사 완료 핸들러 (Step 500)
/// 모터 OFF, 완료 이벤트 발생, Idle 복귀
/// </summary>
public class CompleteHandler : IStepHandler
{
    private readonly IoBoardService _ioBoard;
    private readonly IInspectionCallback _callback;

    public CompleteHandler(IoBoardService ioBoard, IInspectionCallback callback)
    {
        _ioBoard = ioBoard;
        _callback = callback;
    }

    public InspectionStep Execute(InspectionContext context)
    {
        _callback.RaiseLog("검사 완료");

        // 모터 OFF
        _ioBoard.OFF();
        _ioBoard.SendDoFrame();

        // 완료 이벤트 발생
        _callback.RaiseCompleted();

        return InspectionStep.Idle;
    }
}

