using PortableTestMachine2.Communication;
using PortableTestMachine2.Models;

namespace PortableTestMachine2.Inspection.StepHandlers;

/// <summary>
/// CCW 방향 측정 핸들러 (Step 300~303)
/// CCW 구동 → 전류 측정 → 완료 처리 → 대기 → CycleCount 전환
/// </summary>
public class CcwMeasureHandler : IStepHandler
{
    private readonly PowerSupplyService _supply;
    private readonly IoBoardService _ioBoard;
    private readonly IInspectionCallback _callback;

    public CcwMeasureHandler(
        PowerSupplyService supply,
        IoBoardService ioBoard,
        IInspectionCallback callback)
    {
        _supply = supply;
        _ioBoard = ioBoard;
        _callback = callback;
    }

    public InspectionStep Execute(InspectionContext context)
    {
        switch (context.CurrentStep)
        {
            case InspectionStep.CcwStart:
                return HandleCcwStart(context);

            case InspectionStep.CcwMeasure:
                return HandleCcwMeasure(context);

            case InspectionStep.CcwComplete:
                return HandleCcwComplete(context);

            case InspectionStep.CcwWait:
                return HandleCcwWait(context);

            default:
                return context.CurrentStep;
        }
    }

    /// <summary>
    /// CCW 구동 시작 — 모터 CCW, 샘플 초기화
    /// </summary>
    private InspectionStep HandleCcwStart(InspectionContext context)
    {
        _ioBoard.CCW();
        _ioBoard.SendDoFrame();
        context.ResetSamples();
        _callback.RaiseLog($"CCW 구동 시작 (반복 {context.TestCount + 1}/{context.TargetCount})");

        return InspectionStep.CcwMeasure;
    }

    /// <summary>
    /// CCW 전류 측정 — 정지 조건 확인
    /// </summary>
    private InspectionStep HandleCcwMeasure(InspectionContext context)
    {
        double current = _supply.CurrentValue;
        double elapsed = context.ElapsedSeconds;
        double graphTime = context.GraphSeconds;

        // 샘플 기록
        context.CurrentSamples.Add(current);
        context.TimeSamples.Add(elapsed);
        _callback.RaiseDataPoint(graphTime, current);

        // 최대 전류 계산 (앞뒤 1초 제외)
        if (elapsed > 1.0)
        {
            context.MaxCurrent = CalculateMaxCurrent(context);
        }

        // 정지 조건 판정
        if (CheckStopCondition(context, current, elapsed))
        {
            return InspectionStep.CcwComplete;
        }

        return InspectionStep.CcwMeasure;
    }

    /// <summary>
    /// CCW 완료 처리 — 결과 생성, 모터 OFF
    /// </summary>
    private InspectionStep HandleCcwComplete(InspectionContext context)
    {
        // 최종 최대 전류 계산
        context.MaxCurrent = CalculateMaxCurrent(context);

        var result = new MeasureResult
        {
            SequenceNo = context.Results.Count + 1,
            Direction = "CCW",
            Voltage = context.TargetVolt,
            MaxCurrent = context.MaxCurrent,
            ElapsedTime = context.ElapsedSeconds
        };

        context.Results.Add(result);
        _callback.RaiseResult(result);
        _callback.RaiseLog($"CCW 완료 — 최대전류: {result.MaxCurrent:F3}A, 시간: {result.ElapsedTime:F1}s");

        _ioBoard.OFF();
        _ioBoard.SendDoFrame();
        context.StepTimer.Restart();

        return InspectionStep.CcwWait;
    }

    /// <summary>
    /// CCW 후 1초 대기
    /// </summary>
    private static InspectionStep HandleCcwWait(InspectionContext context)
    {
        if (context.ElapsedSeconds > 1.0)
        {
            return InspectionStep.CycleCount;
        }
        return InspectionStep.CcwWait;
    }

    /// <summary>
    /// 정지 조건 확인
    /// </summary>
    private static bool CheckStopCondition(InspectionContext context, double current, double elapsed)
    {
        switch (context.StopMode)
        {
            case "CURRENT":
                return current >= context.StopValue && elapsed > 1.0;

            case "TIME":
                return elapsed >= context.StopValue;

            default:
                return false;
        }
    }

    /// <summary>
    /// 최대 전류 계산 — 앞 1초, 뒤 1초 구간 제외
    /// </summary>
    private static double CalculateMaxCurrent(InspectionContext context)
    {
        double maxCurrent = 0;
        double totalElapsed = context.ElapsedSeconds;

        for (int i = 0; i < context.TimeSamples.Count; i++)
        {
            double t = context.TimeSamples[i];
            if (t > 1.0 && t < totalElapsed - 1.0)
            {
                if (context.CurrentSamples[i] > maxCurrent)
                {
                    maxCurrent = context.CurrentSamples[i];
                }
            }
        }

        return maxCurrent;
    }
}

