using PortableTestMachine2.Communication;

namespace PortableTestMachine2.Inspection.StepHandlers;

/// <summary>
/// 반복 카운트 핸들러 (Step 400)
/// 반복 횟수 판정 — 미달이면 다음 사이클, 도달이면 완료
/// </summary>
public class CycleCountHandler : IStepHandler
{
    private readonly IoBoardService _ioBoard;
    private readonly IInspectionCallback _callback;

    public CycleCountHandler(IoBoardService ioBoard, IInspectionCallback callback)
    {
        _ioBoard = ioBoard;
        _callback = callback;
    }

    public InspectionStep Execute(InspectionContext context)
    {
        // 반복 카운트 증가
        context.TestCount++;

        // 모터 OFF
        _ioBoard.OFF();
        _ioBoard.SendDoFrame();

        // 반복 횟수 판정
        if (context.TestCount < context.TargetCount)
        {
            _callback.RaiseLog($"반복 {context.TestCount}/{context.TargetCount} 완료 — 다음 사이클");
            return InspectionStep.CycleStart;
        }
        else
        {
            return InspectionStep.Complete;
        }
    }
}

