/// <summary>
/// 검사 시작 — 백그라운드 스레드 실행
/// </summary>
public void Start()
{
    if (_running) return;

    _running = true;
    _context.Reset();
    _context.CurrentStep = InspectionStep.SetVoltage;

    _thread = new Thread(RunLoop)
    {
        Name = "InspectionEngine",
        IsBackground = true
    };
    _thread.Start();
}
